<template>
  <div class="hero is-fullheight-with-navbar">
    <div class="hero-body">
      <div class="container">
        <h1 class="title has-text-grey-dark">分类</h1>
        <div class="field is-grouped is-grouped-multiline">
          <div
            class="control"
            v-bind:key="index"
            v-for="(classification, index) in classifications"
          >
            <router-link
              class="tags has-addons are-large"
              v-bind:to="'/classification/archive/' + classification.classification.id + '/'"
            >
              <span class="tag is-dark" v-text="classification.classification.name"></span>
              <span class="tag is-info" v-text="classification.classificationQuantity"></span>
            </router-link>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      classifications: []
    }
  },
  mounted: function() {
    this.$store.dispatch('progress', true)
    const url = process.env.VUE_APP_HOST + 'article/classification/'
    this.$axios.get(url).then(
      function(response) {
        this.classifications = response.data
        this.$store.dispatch('progress', false)
      }.bind(this)
    )
  }
}
</script>
