<template>
  <div class="hero is-dark is-fullheight-with-navbar">
    <div class="hero-body">
      <div class="container">
        <div class="tile is-ancestor is-vertical">
          <div class="tile">
            <div class="tile is-parent is-vertical">
              <div class="tile is-child notification is-success">
                <h1 class="title" v-text="title"></h1>
              </div>
              <div class="tile is-child notification is-light">
                <div class="content" ref="html" v-html="html"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      title: '语法指南',
      html: ''
    }
  },
  mounted: function() {
    this.getAbout()
  },
  methods: {
    getAbout: function() {
      this.$store.dispatch('progress', true)
      const url =
        'https://gist.githubusercontent.com/cciradih/37ba6f8f1d73cf0eef0f7d2e2614ad5f/raw/3df5c755d962f5277a716a348f5f70c9bc889ba9/syntax'
      this.$axios.get(url).then(
        function(response) {
          this.html = this.$marked(response.data)
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    }
  },
  watch: {
    html: function() {
      this.$nextTick().then(
        function() {
          if (window.MathJax) {
            window.MathJax.Hub.Queue([
              'Typeset',
              window.MathJax.Hub,
              this.$refs.html
            ])
          }
        }.bind(this)
      )
    }
  }
}
</script>
