<template>
  <div class="hero is-fullheight-with-navbar">
    <div class="hero-body">
      <div class="container">
        <div class="table-container">
          <table class="table is-fullwidth is-striped is-hoverable">
            <thead>
              <tr>
                <th
                  v-bind:key="index"
                  v-for="(metaHeader, index) in metaHeaders"
                  v-text="metaHeader"
                ></th>
              </tr>
            </thead>
            <tbody>
              <tr v-bind:key="index" v-for="(meta, index) in metas">
                <td v-text="meta.title"></td>
                <td v-text="new Date(meta.date).toLocaleDateString()"></td>
                <td>
                  <div class="field has-addons">
                    <div class="control">
                      <div class="button" v-on:click="update(meta.id)">
                        <span class="icon is-small">
                          <i class="fas fa-edit"></i>
                        </span>
                      </div>
                    </div>
                    <div class="control">
                      <div
                        class="button"
                        v-on:click="remove(meta.classificationId, meta.contentId, meta.id)"
                      >
                        <span class="icon is-small">
                          <i class="fas fa-trash"></i>
                        </span>
                      </div>
                    </div>
                  </div>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
        <div class="modal" v-bind:class="{ 'is-active': submitActive }">
          <div class="modal-background" v-on:click.stop="submitActive = false"></div>
          <div class="modal-card">
            <div class="modal-card-head">
              <div class="modal-card-title">提交</div>
              <div class="delete" v-on:click.stop="submitActive = false"></div>
            </div>
            <div class="modal-card-body">
              <div class="field">
                <div class="control has-icons-left">
                  <span class="icon is-small is-left">
                    <i class="fas fa-heading"></i>
                  </span>
                  <input class="input" type="text" v-model="meta.title" />
                </div>
              </div>
              <div class="field">
                <div class="control has-icons-left">
                  <span class="icon is-small is-left">
                    <i class="fas fa-tag"></i>
                  </span>
                  <input
                    class="input"
                    list="classificationList"
                    type="text"
                    v-model="classification.name"
                  />
                  <datalist id="classificationList">
                    <option
                      v-bind:key="index"
                      v-for="(classification, index) in classifications"
                      v-text="classification.classification.name"
                    ></option>
                  </datalist>
                </div>
              </div>
              <div class="field">
                <div class="control has-icons-left">
                  <span class="icon is-small is-left">
                    <i class="fab fa-markdown"></i>
                  </span>
                  <textarea class="textarea has-fixed-size" rows="25" v-model="content.markdown" />
                </div>
              </div>
            </div>
            <div class="modal-card-foot">
              <div class="button is-success" v-on:click="submit()">提交</div>
            </div>
          </div>
        </div>
      </div>
    </div>
    <div class="hero-foot">
      <nav class="tabs is-boxed is-fullwidth is-large">
        <div class="container">
          <ul>
            <li>
              <a class="pagination-previous" v-on:click="create()">
                <span class="icon">
                  <i class="fas fa-plus"></i>
                </span>
              </a>
            </li>
            <li>
              <a class="pagination-previous" v-if="previousShow" v-on:click="getAll(page -= 1)">
                <span class="icon">
                  <i class="fas fa-chevron-left"></i>
                </span>
              </a>
            </li>
            <li>
              <a class="pagination-next" v-if="nextShow" v-on:click="getAll(page += 1)">
                <span class="icon">
                  <i class="fas fa-chevron-right"></i>
                </span>
              </a>
            </li>
          </ul>
        </div>
      </nav>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      metaHeaders: ['标题', '时间', '操作'],
      metas: [],
      classifications: [],
      submitActive: false,
      classification: {},
      content: {},
      meta: {},
      type: '',
      totalPage: 0,
      page: 0,
      previousShow: false,
      nextShow: false
    }
  },
  mounted: function() {
    this.getAll(0)
  },
  methods: {
    getAll: function(page) {
      this.$store.dispatch('progress', true)
      const url =
        process.env.VUE_APP_HOST +
        'article/?page=' +
        page +
        '&size=12&sort=date,desc'
      this.$axios.get(url).then(
        function(response) {
          this.totalPage = response.data.metaTotalPage
          this.metas = response.data.metas
          if (
            response.data.metaTotalPage !== 1 &&
            response.data.metaTotalPage
          ) {
            if (page === 0) {
              this.previousShow = false
            } else {
              this.previousShow = true
            }
            if (page === response.data.metaTotalPage - 1) {
              this.nextShow = false
            } else {
              this.nextShow = true
            }
          } else {
            this.previousShow = false
            this.nextShow = false
          }
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    },
    getAllClassification: function() {
      this.$store.dispatch('progress', true)
      const url = process.env.VUE_APP_HOST + 'article/classification/'
      this.$axios.get(url).then(
        function(response) {
          this.classifications = response.data
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    },
    submit: function() {
      this.$store.dispatch('progress', true)
      const url = process.env.VUE_APP_HOST + 'article/'
      const config = {
        withCredentials: true
      }
      const data = {
        classification: this.classification,
        content: this.content,
        meta: this.meta
      }
      switch (this.type) {
        case 'create':
          data.meta.date = new Date()
          this.$axios.post(url, data, config).then(
            function(response) {
              this.getAll(this.page)
              this.submitActive = false
              this.$store.dispatch('progress', false)
            }.bind(this)
          )
          break
        case 'update':
          this.$axios.put(url, data, config).then(
            function(response) {
              this.getAll(this.page)
              this.submitActive = false
              this.$store.dispatch('progress', false)
            }.bind(this)
          )
          break
      }
    },
    create: function() {
      this.meta = {}
      this.classification = {}
      this.content = {}
      this.getAllClassification()
      this.type = 'create'
      this.submitActive = true
    },
    update: function(metaId) {
      this.$store.dispatch('progress', true)
      const url = process.env.VUE_APP_HOST + 'article/' + metaId + '/'
      this.$axios.get(url).then(
        function(response) {
          this.meta = response.data.meta
          this.classification = response.data.classification
          this.content = response.data.content
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
      this.getAllClassification()
      this.type = 'update'
      this.submitActive = true
    },
    remove: function(classificationId, contentId, metaId) {
      this.$store.dispatch('progress', true)
      const url = process.env.VUE_APP_HOST + 'article/'
      const config = {
        withCredentials: true,
        data: {
          meta: {
            classificationId: classificationId,
            contentId: contentId,
            id: metaId
          }
        }
      }
      this.$axios.delete(url, config).then(
        function(response) {
          this.getAll(this.page)
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    }
  }
}
</script>
