<template>
  <div class="hero is-fullheight-with-navbar">
    <div class="hero-body">
      <div class="container">
        <h1 class="title has-text-grey-dark">归档</h1>
        <div class="columns is-multiline">
          <div class="column is-3" v-bind:key="index" v-for="(meta, index) in metas">
            <div class="card">
              <div class="card-content">
                <div class="title" v-text="meta.title"></div>
                <div class="subtitle" v-text="new Date(meta.date).toLocaleDateString()"></div>
              </div>
              <footer class="card-footer">
                <router-link class="card-footer-item" v-bind:to="'/article/' + meta.id + '/'">
                  <span class="icon">
                    <i class="fas fa-eye"></i>
                  </span>
                </router-link>
              </footer>
            </div>
          </div>
        </div>
      </div>
    </div>
    <div class="hero-foot">
      <nav class="tabs is-boxed is-fullwidth is-large">
        <div class="container">
          <ul>
            <li>
              <a class="pagination-previous" v-if="previousShow" v-on:click="getAll(page -= 1)">
                <span class="icon">
                  <i class="fas fa-chevron-left"></i>
                </span>
              </a>
            </li>
            <li>
              <a class="pagination-next" v-if="nextShow" v-on:click="getAll(page += 1)">
                <span class="icon">
                  <i class="fas fa-chevron-right"></i>
                </span>
              </a>
            </li>
          </ul>
        </div>
      </nav>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      metas: [],
      page: 0,
      totalPage: 0,
      previousShow: false,
      nextShow: false
    }
  },
  mounted: function() {
    if (this.$route.params.classificationId) {
      this.getByClassification(0)
    } else {
      this.getAll(0)
    }
  },
  methods: {
    getAll: function(page) {
      this.$store.dispatch('progress', true)
      const url =
        process.env.VUE_APP_HOST +
        'article/?page=' +
        page +
        '&size=12&sort=date,desc'
      this.$axios.get(url).then(
        function(response) {
          this.totalPage = response.data.metaTotalPage
          this.metas = response.data.metas
          if (
            response.data.metaTotalPage !== 1 &&
            response.data.metaTotalPage
          ) {
            if (page === 0) {
              this.previousShow = false
            } else {
              this.previousShow = true
            }
            if (page === response.data.metaTotalPage - 1) {
              this.nextShow = false
            } else {
              this.nextShow = true
            }
          } else {
            this.previousShow = false
            this.nextShow = false
          }
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    },
    getByClassification: function(page) {
      this.$store.dispatch('progress', true)
      const url =
        process.env.VUE_APP_HOST +
        'article/classification/' +
        this.$route.params.classificationId +
        '/?page=' +
        page +
        '&size=16&sort=date,desc'
      this.$axios.get(url).then(
        function(response) {
          this.totalPage = response.data.metaTotalPage
          this.metas = response.data.metas
          if (
            response.data.metaTotalPage !== 1 &&
            response.data.metaTotalPage
          ) {
            if (page === 0) {
              this.previousShow = false
            } else {
              this.previousShow = true
            }
            if (page === response.data.metaTotalPage - 1) {
              this.nextShow = false
            } else {
              this.nextShow = true
            }
          } else {
            this.previousShow = false
            this.nextShow = false
          }
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    }
  },
  watch: {
    $route: function() {
      this.getAll(0)
    }
  }
}
</script>
