import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    loginStatus: false || sessionStorage.getItem('loginStatus'),
    progressStatus: false
  },
  mutations: {
    login(state, loginStatus) {
      state.loginStatus = loginStatus
    },
    progress(state, progressStatus) {
      state.progressStatus = progressStatus
    }
  },
  actions: {
    login(context, loginStatus) {
      context.commit('login', loginStatus)
    },
    progress(context, progressStatus) {
      context.commit('progress', progressStatus)
    }
  }
})
