<template>
  <div class="hero is-dark is-fullheight-with-navbar">
    <div class="hero-body">
      <div class="container">
        <div class="tile is-ancestor is-vertical">
          <div class="tile">
            <div class="tile is-parent is-vertical">
              <div class="tile is-child notification is-success">
                <h1 class="title" v-text="title"></h1>
                <div class="tags has-addons are-large">
                  <span class="tag is-dark" v-text="classification"></span>
                  <span class="tag is-info" v-text="date"></span>
                </div>
              </div>
              <div class="tile is-child notification is-light">
                <div class="content" ref="html" v-html="html"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      title: '',
      date: '',
      classification: '',
      html: ''
    }
  },
  mounted: function() {
    this.getArticleById()
  },
  methods: {
    getArticleById: function() {
      this.$store.dispatch('progress', true)
      const metaId = this.$route.params.metaId
      const url = process.env.VUE_APP_HOST + 'article/' + metaId + '/'
      this.$axios.get(url).then(
        function(response) {
          this.title = response.data.meta.title
          this.date = new Date(response.data.meta.date).toLocaleDateString()
          this.classification = response.data.classification.name
          this.html = this.$marked(response.data.content.markdown)
          this.$store.dispatch('progress', false)
        }.bind(this)
      )
    }
  },
  watch: {
    html: function() {
      this.$nextTick().then(
        function() {
          if (window.MathJax) {
            window.MathJax.Hub.Queue([
              'Typeset',
              window.MathJax.Hub,
              this.$refs.html
            ])
          }
        }.bind(this)
      )
    }
  }
}
</script>
