import Vue from 'vue'
import VueRouter from 'vue-router'
import Archive from '../views/Archive.vue'
import Article from '../views/Article.vue'
import Classification from '../views/Classification.vue'
import Home from '../views/Home.vue'
import Manager from '../views/Manager.vue'
import Syntax from '../views/Syntax.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '*',
    name: '404',
    component: Home
  },
  {
    path: '/archive/',
    name: 'archive',
    component: Archive
  },
  {
    path: '/article/:metaId/',
    name: 'article',
    component: Article
  },
  {
    path: '/classification/',
    name: 'classification',
    component: Classification
  },
  {
    path: '/classification/archive/:classificationId',
    name: 'classificationArchive',
    component: Archive
  },
  {
    path: '/',
    name: 'home',
    component: Home
  },
  {
    path: '/manager/',
    name: 'manager',
    component: Manager,
    meta: {
      auth: true
    }
  },
  {
    path: '/syntax/',
    name: 'syntax',
    component: Syntax
  }
]

const router = new VueRouter({
  routes
})

export default router
