          </div>
        </div>
        <div class="navbar-menu" v-bind:class="{ 'is-active': navbarMenuActive }">
          <div class="navbar-start">
            <router-link
              class="navbar-item"
              v-bind:key="index"
              v-bind:to="navigation.path"
              v-for="(navigation, index) in navigations"
            >
              <span class="icon">
                <i v-bind:class="navigation.icon"></i>
              </span>
            </router-link>
          </div>
          <div class="navbar-end">
            <div class="navbar-item">
              <div class="field is-grouped">
                <div class="control" v-if="!loginStatus">
                  <div class="button is-success" v-on:click.stop="loginActive = true">
                    <span class="icon is-small">
                      <i class="fas fa-sign-in-alt"></i>
                    </span>
                  </div>
                </div>
                <div class="control" v-if="loginStatus">
                  <router-link class="button is-primary" to="/manager/">
                    <span class="icon is-small">
                      <i class="fas fa-cog"></i>
                    </span>
                  </router-link>
                </div>
                <div class="control" v-if="loginStatus">
                  <div class="button is-danger" v-on:click="logout()">
                    <span class="icon is-small">
                      <i class="fas fa-sign-out-alt"></i>
                    </span>
                  </div>
                </div>
              </div>
