          <div class="column">
            <div class="subtitle">版权与协议</div>
            <div class="subtitle">© 2016 - {{ new Date().getFullYear() }} Cciradih.top</div>
            <div class="field is-grouped is-grouped-multiline">
              <div class="control" v-bind:key="index" v-for="(license, index) in licenses">
                <a class="tags has-addons" v-bind:href="license.path">
                  <span class="tag is-success" v-text="license.name"></span>
                  <span class="tag is-info" v-text="license.version"></span>
                </a>
              </div>
            </div>
          </div>
          <div class="column">
            <div class="subtitle">联系</div>
            <div class="field is-grouped is-grouped-multiline">
              <div class="control" v-bind:key="index" v-for="(contact, index) in contacts">
                <a class="tags has-addons" v-bind:href="contact.path">
                  <span class="tag icon is-danger">
                    <i v-bind:class="contact.icon"></i>
                  </span>
                  <span class="tag is-primary" v-text="contact.name"></span>
                </a>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    <div class="modal" v-bind:class="{ 'is-active': loginActive }">
      <div class="modal-background" v-on:click.stop="loginActive = false"></div>
      <div class="modal-card">
        <div class="modal-card-head">
          <div class="modal-card-title">登录</div>
          <div class="delete" v-on:click.stop="loginActive = false"></div>
        </div>
        <div class="modal-card-body">
          <div class="field">
            <div class="control has-icons-left">
              <span class="icon is-small is-left">
                <i class="fas fa-user"></i>
              </span>
              <input class="input" type="text" v-bind:class="loginError" v-model="username" />
            </div>
          </div>
          <div class="field">
            <div class="control has-icons-left">
              <span class="icon is-small is-left">
                <i class="fas fa-key"></i>
              </span>
              <input
                autocomplete="new-password"
                class="input"
                type="password"
                v-bind:class="loginError"
                v-model="password"
              />
            </div>
          </div>
        </div>
        <div class="modal-card-foot">
          <div class="button is-success" v-on:click="login()">
            <span class="icon is-small">
              <i class="fas fa-sign-in-alt"></i>
            </span>
          </div>
        </div>
      </div>
    </div>
    <div class="modal" v-bind:class="{'is-active': progressStatus}">
      <div class="modal-background"></div>
      <div class="modal-content">
        <progress class="progress is-small is-dark"></progress>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  data: function() {
    return {
      navbarMenuActive: false,
      navigations: [
        {
          path: '/',
          icon: 'fas fa-home'
        },
        {
          path: '/classification/',
          icon: 'fas fa-tags'
        },
        {
          path: '/archive/',
          icon: 'fas fa-archive'
        },
        {
          path: '/syntax/',
          icon: 'fas fa-info'
        }
      ],
      licenses: [
        {
          path: 'https://creativecommons.org/licenses/by-nc-sa/4.0/legalcode',
          name: 'BY-NC-SA',
          version: '4.0'
        },
        {
          path: 'https://www.gnu.org/licenses/gpl-3.0-standalone.html',
          name: 'GNU GPL',
          version: '3.0'
        }
      ],
      contacts: [
        {
          path: 'https://github.com/cciradih/',
          icon: 'fab fa-github',
          name: 'Cciradih'
        },
        {
          path:
            'https://shang.qq.com/wpa/qunwpa?idkey=18ce00de201537ad6cb4eb43577815ef44a5b8a03c6f2c6ab7a9ddfa789e3848',
          icon: 'fab fa-qq',
          name: '883635575'
        },
        {
          path: 'mailto:mountain@cciradih.top',
          icon: 'fas fa-envelope',
          name: 'mountain@cciradih.top'
        }
      ],
      loginActive: false,
      username: '',
      password: '',
      loginError: ''
    }
  },
  methods: {
    login: function() {
      this.$store.dispatch('progress', true)
      const url = process.env.VUE_APP_HOST + 'user/login/'
      const config = {
        withCredentials: true,
        auth: {
          username: this.username,
          password: this.password
        }
      }
      this.$axios
        .post(url, {}, config)
        .then(
          function(response) {
            this.loginError = ''
            this.$store.dispatch('login', true)
            sessionStorage.setItem('loginStatus', true)
            this.loginActive = false
            this.$router.push('/manager/')
            this.$store.dispatch('progress', false)
          }.bind(this)
        )
        .catch(
          function() {
            this.loginError = 'is-danger'
            this.$store.dispatch('login', false)
            sessionStorage.removeItem('loginStatus')
            this.$store.dispatch('progress', false)
          }.bind(this)
        )
    },
    logout: function() {
      this.$store.dispatch('login', false)
      sessionStorage.removeItem('loginStatus')
      window.location.href = process.env.VUE_APP_HOST + 'user/logout/'
    }
  },
  computed: {
    progressStatus: function() {
      return this.$store.state.progressStatus
    },
    loginStatus: function() {
      return this.$store.state.loginStatus
    }
  }
}
</script>
<style scoped>
#app {
  font-family: 'Noto Sans SC', sans-serif;
  user-select: none;
}
